### 4. COMPLEX BATCH OPERATIONS & TRANSACTIONS

#### Bulk Upsert Pattern (Category Correlations)

**File**: `/src/modules/db/category-correlations/models/category-correlation.model.ts`

```typescript
async bulkUpsert(
  correlations: {
    primaryCategoryId: number;
    edgeId: number;
    edgeWeight: number;
  }[],
): Promise<void> {
  const dataToInsert = correlations.map((correlation) => ({
    _id: randomUUID(),
    primary_category_id: correlation.primaryCategoryId,
    edge_id: correlation.edgeId,
    edge_weight: correlation.edgeWeight,
    created_at: this.knexWrite.fn.now(),
    updated_at: this.knexWrite.fn.now(),
    deleted_at: null,
  }));

  const batchSize = 1000;  // Process in 1000-record batches
  for (let i = 0; i < dataToInsert.length; i += batchSize) {
    const batch = dataToInsert.slice(i, i + batchSize);

    // MySQL ON CONFLICT ... MERGE for upsert
    await this.knexWrite(this.tableName)
      .insert(batch)
      .onConflict(['primary_category_id', 'edge_id'])
      .merge(['edge_weight', 'updated_at', 'deleted_at']);

    this.logger.debug(
      `Processed batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(dataToInsert.length / batchSize)}`,
    );
  }
}
```

#### Batch Predictions with Transactions

**File**: `/src/modules/db/forecasted-trending-products/models/forecasted-trending-products.model.ts`

```typescript
async saveBatchPredictions({
  predictions,
}: {
  predictions: ITrendingProductsCreate[];
}): Promise<ITrendingProductsBase[]> {
  return await this.knexWrite.transaction(async (trx) => {
    // Validate all predictions
    const validationResults = await Promise.all(
      predictions.map(async (prediction) => {
        const dto = plainToInstance(CreateTrendingProductsDto, prediction);
        const errors = await validate(dto);
        return { prediction, errors };
      }),
    );

    // Filter out invalid predictions
    const validatedPredictions = validationResults
      .filter(({ errors }) => errors.length === 0)
      .map(({ prediction }) => prediction);

    // Transform for storage (JSON serialization)
    const insertData = validatedPredictions.map((prediction) => ({
      _id: randomUUID(),
      style_id: Number(prediction.style_id),
      is_latest: 1,
      is_active: 0,
      predicted_orders: JSON.stringify(prediction.predicted_orders),
      total_predicted_orders: prediction.total_predicted_orders,
      trend_score: prediction.trend_score,
      trending_reason: prediction.trending_reason,
      forecast_start_date: prediction.forecast_start_date,
      forecast_end_date: prediction.forecast_end_date,
      forecast_days: prediction.forecast_days,
      created_at: trx.fn.now(),
      updated_at: trx.fn.now(),
    }));

    // Insert in transaction
    await trx(TABLE_NAME_TRENDING_PRODUCTS).insert(insertData);

    // Retrieve and validate inserted data
    const results = await trx<BaseTrendingProductsDto>(TABLE_NAME_TRENDING_PRODUCTS)
      .whereIn('_id', insertData.map((item) => item._id))
      .orderBy('created_at', 'desc');

    return results;  // Return validated results
  });
}
```

