**Upsert with Transaction**:
```typescript
const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
  const existing = await trx<IStyleBase>(this.tableName)
    .where({ style_id: data.style_id })
    .whereNull('deleted_at')
    .first();

  if (existing) {
    // Update existing
    await trx(this.tableName)
      .where({ style_id: data.style_id })
      .whereNull('deleted_at')
      .update(updateData);
  } else {
    // Insert new
    await trx(this.tableName).insert(insertData);
  }

  // Fetch result within transaction
  return await trx<IStyleBase>(this.tableName)
    .where({ style_id: data.style_id })
    .whereNull('deleted_at')
    .first();
});
```

**Complex Multi-Table Transaction**:
```typescript
async saveCompleteStyle({
  styleData,
  colors,
  defaultUnitPrices,
}: {
  styleData: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
  colors: Omit<IStyleColorCreate, 'style_id'>[];
  defaultUnitPrices: Omit<IDefaultUnitPriceCreate, 'style_id'>[];
}): Promise<void> {
  try {
    await this.knexWrite.transaction(async (trx) => {
      // Upsert style
      await this.upsertStyleWithTransaction({ trx, data: styleData });

      // Upsert related colors
      for (const color of colors) {
        await this.styleColorModel.upsertStyleWithTransaction({
          trx,
          data: { style_id: styleData.style_id, ...color },
        });
      }

      // Upsert prices
      for (const priceData of defaultUnitPrices) {
        await this.defaultUnitPriceModel.upsertWithTransaction({
          trx,
          data: { style_id: styleData.style_id, ...priceData },
        });
      }
    });
  } catch (error) {
    // Error handling
  }
}
```

