@Injectable()
export class StylesHashService {
  constructor(private readonly stylesHashModel: StylesHashModel) {}

  async createStyleHash({ data }: { data: IStylesHashCreate }): Promise<IStylesHashBase> {
    return this.stylesHashModel.create({ data });
  }

  async getStyleHash({ styleId }: { styleId: number }): Promise<IStylesHashBase | null> {
    return this.stylesHashModel.findByStyleId({ styleId });
